style:
it-alert .agid-alert{padding:var(--it-space-md);border-radius:var(--it-radius-sm);background:var(--it-color-info-bg);color:var(--it-color-info-accent);border-left:4px solid var(--it-color-info-accent)}
it-alert[variant="success"] .agid-alert{background:var(--it-color-success-bg);color:var(--it-color-success-accent);border-left-color:var(--it-color-success-accent)}
it-alert[variant="warning"] .agid-alert{background:var(--it-color-warning-bg);color:var(--it-color-warning-accent);border-left-color:var(--it-color-warning-accent)}
it-alert[variant="danger"] .agid-alert{background:#fdecea;color:#b3261e;border-left-color:#b3261e}
